// // This module performs a complex HMAC operation with a 16-bit key and message, producing a 16-bit HMAC output.
module hmac_simple (  
    input [7:0] key,  
    input [7:0] message,  
    output [7:0] hmac  
);  
    assign hmac = key ^ message; // Simple HMAC using XOR as the hash function  
endmodule
